<?php declare(strict_types=1); namespace App\Services\Attendance; use App\Enums\LeaveStatus; use App\Models\EmployeeLeaveRequest; use App\Models\EmployeeAttendance; use App\Services\ActivityLogger; use Illuminate\Http\UploadedFile; use Illuminate\Support\Carbon; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class LeaveRequestService{public function __construct(private ActivityLogger $logger){} public function create(array $data,?UploadedFile $file=null):EmployeeLeaveRequest{$path=$file?->store('employee-leaves','private'); return DB::transaction(function()use($data,$path){$overlap=EmployeeLeaveRequest::where('employee_id',$data['employee_id'])->whereNotIn('status',[LeaveStatus::Rejected->value,LeaveStatus::Cancelled->value])->whereDate('starts_at','<=',$data['ends_at'])->whereDate('ends_at','>=',$data['starts_at'])->exists(); if($overlap)throw ValidationException::withMessages(['starts_at'=>'Tanggal izin tumpang tindih.']); $leave=EmployeeLeaveRequest::create($data+['attachment_path'=>$path,'status'=>LeaveStatus::Pending]); $this->logger->log('employee-leave.created',$leave,[],$leave->toArray()); return $leave;});} public function approve(EmployeeLeaveRequest $l):void{DB::transaction(function()use($l){$old=$l->toArray();$l->update(['status'=>LeaveStatus::Approved,'approved_by'=>auth()->id(),'approved_at'=>now()]); for($d=$l->starts_at->copy();$d->lte($l->ends_at);$d->addDay()){EmployeeAttendance::updateOrCreate(['employee_id'=>$l->employee_id,'attendance_date'=>$d->toDateString()],['status'=>$l->type->attendanceStatus(),'notes'=>'Referensi pengajuan izin #'.$l->id,'created_by'=>auth()->id()]);} $this->logger->log('employee-leave.approved',$l,$old,$l->fresh()->toArray());});} public function reject(EmployeeLeaveRequest $l,string $reason):void{$old=$l->toArray();$l->update(['status'=>LeaveStatus::Rejected,'rejection_reason'=>$reason,'approved_by'=>auth()->id(),'approved_at'=>now()]);$this->logger->log('employee-leave.rejected',$l,$old,$l->fresh()->toArray(),$reason);}}
